// clone.go
package planaddons

import (
	"context"
	"net/http"

	api "github.com/openmeterio/openmeter/api/v3"
	"github.com/openmeterio/openmeter/api/v3/apierrors"
	"github.com/openmeterio/openmeter/api/v3/request"
	"github.com/openmeterio/openmeter/openmeter/productcatalog/planaddon"
	"github.com/openmeterio/openmeter/pkg/framework/commonhttp"
	"github.com/openmeterio/openmeter/pkg/framework/transport/httptransport"
	"github.com/openmeterio/openmeter/pkg/models"
)

type (
	ClonePlanAddonRequest  = planaddon.ClonePlanAddonInput
	ClonePlanAddonResponse = api.PlanAddon
	ClonePlanAddonParams   struct {
		PlanID      string
		PlanAddonID string
	}
	ClonePlanAddonHandler httptransport.HandlerWithArgs[ClonePlanAddonRequest, ClonePlanAddonResponse, ClonePlanAddonParams]
)

func (h *handler) ClonePlanAddon() ClonePlanAddonHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, params ClonePlanAddonParams) (ClonePlanAddonRequest, error) {
			body := api.ClonePlanAddonRequest{}
			if err := request.ParseBody(r, &body); err != nil {
				return ClonePlanAddonRequest{}, err
			}
			ns, err := h.resolveNamespace(ctx)
			if err != nil {
				return ClonePlanAddonRequest{}, err
			}
			return ClonePlanAddonRequest{
				NamespacedModel: models.NamespacedModel{Namespace: ns},
				ID:     params.PlanAddonID,
				PlanID: params.PlanID,
			}, nil
		},
		func(ctx context.Context, req ClonePlanAddonRequest) (ClonePlanAddonResponse, error) {
			a, err := h.addonService.ClonePlanAddon(ctx, req)
			if err != nil {
				return ClonePlanAddonResponse{}, err
			}
			return ToAPIPlanAddon(*a)
		},
		commonhttp.JSONResponseEncoderWithStatus[ClonePlanAddonResponse](http.StatusCreated),
		httptransport.AppendOptions(
			h.options,
			httptransport.WithOperationName("clone-plan-addon"),
			httptransport.WithErrorEncoder(apierrors.GenericErrorEncoder()),
		)...,
	)
}
